import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Token 省量三大策略：上下文管理 / 提示詞工程 / MCP 清理 — @yanhua1010","description":"","frontmatter":{"title":"Claude Token 省量三大策略：上下文管理 / 提示詞工程 / MCP 清理 — @yanhua1010","author":"Yanhua（@yanhua1010）","date":"2026-03-27T00:00:00.000Z","source":"https://x.com/yanhua1010/status/2037460564746858514（Thread","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-27-@yanhua1010-858514.md","filePath":"research/tweets/2026-03-27-@yanhua1010-858514.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-03-27-@yanhua1010-858514.md"};function d(l,t,h,s,i,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-token-省量三大策略-上下文管理-提示詞工程-mcp-清理-—-yanhua1010" tabindex="-1">Claude Token 省量三大策略：上下文管理 / 提示詞工程 / MCP 清理 — @yanhua1010 <a class="header-anchor" href="#claude-token-省量三大策略-上下文管理-提示詞工程-mcp-清理-—-yanhua1010" aria-label="Permalink to &quot;Claude Token 省量三大策略：上下文管理 / 提示詞工程 / MCP 清理 — @yanhua1010&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/yanhua1010/status/2037460564746858514%EF%BC%88Thread" target="_blank" rel="noreferrer">https://x.com/yanhua1010/status/2037460564746858514（Thread</a> 共 4 則） <strong>作者</strong>：Yanhua（@yanhua1010） <strong>發布日期</strong>：2026-03-27 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Thread <strong>統計</strong>：30 likes · 6 retweets · 63 bookmarks · 34,179 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><h3 id="引言-2037460564746858514" tabindex="-1">引言（2037460564746858514） <a class="header-anchor" href="#引言-2037460564746858514" aria-label="Permalink to &quot;引言（2037460564746858514）&quot;">​</a></h3><p>💡 Claude 玩家必看：Reddit 大佬们总结的 Token 省钱/省量大法！</p><p>感觉 Claude 的 Token 烧得太快？Reddit 的 r/ClaudeAI 和 r/ClaudeCode 社区最近总结了一套实操性极强的&quot;省钱策略&quot;。</p><p>拒绝无效消耗，建议收藏👇</p><hr><h3 id="_1️⃣-上下文管理-別讓「歷史」拖垮你-2037460567485780335" tabindex="-1">1️⃣ 上下文管理：別讓「歷史」拖垮你（2037460567485780335） <a class="header-anchor" href="#_1️⃣-上下文管理-別讓「歷史」拖垮你-2037460567485780335" aria-label="Permalink to &quot;1️⃣ 上下文管理：別讓「歷史」拖垮你（2037460567485780335）&quot;">​</a></h3><p>开启新对话：每一个新消息都会发送全部历史记录。话题变了就赶紧开新坑，或者用 <code>/clear</code>。</p><p>精简 CLAUDE.md：这个文件是会被持续加载到内存的，越臃肿越烧钱，保持 Lean 状态。</p><p>警惕自动记忆：检查 <code>/memory</code> 是否开启。开启它有时会导致上下文分叉，产生双倍扣费。</p><hr><h3 id="_2️⃣-提示詞工程-拒絕「無效思考」-2037460571797557501" tabindex="-1">2️⃣ 提示詞工程：拒絕「無效思考」（2037460571797557501） <a class="header-anchor" href="#_2️⃣-提示詞工程-拒絕「無效思考」-2037460571797557501" aria-label="Permalink to &quot;2️⃣ 提示詞工程：拒絕「無效思考」（2037460571797557501）&quot;">​</a></h3><p>精准打击：别说「帮我修下 Bug」，直接说「修复 src/auth.ts 里的中间件逻辑」。搜索范围越小，Token 越省。</p><p>慎用 Ultrathink（深度思考）：很多人觉得思考越久效果越好，其实不然。复杂逻辑才用它，普通任务开启它是纯纯的浪费。</p><p>降级策略：不是所有活都要 Opus 4.6。非深度逻辑任务，果断选 Sonnet，性价比之王。</p><hr><h3 id="_3️⃣-工具與-mcp-關掉「偷跑」流量-2037460575379427489" tabindex="-1">3️⃣ 工具與 MCP：關掉「偷跑」流量（2037460575379427489） <a class="header-anchor" href="#_3️⃣-工具與-mcp-關掉「偷跑」流量-2037460575379427489" aria-label="Permalink to &quot;3️⃣ 工具與 MCP：關掉「偷跑」流量（2037460575379427489）&quot;">​</a></h3><p>清理 MCP 服务器：哪怕你没主动用，挂着的 MCP 也会占用上下文。不用的 Server 赶紧关掉。</p><p>本地预处理：别把几千行的原始测试日志直接扔给 Claude。先用本地小模型（如 Llama 3）或低成本模型总结出关键点，再投喂给 Claude。Token 占用最高可降低 99%！</p><p>⚡ 总结一句话：像用流量套餐一样用 Claude：按需开启，用完即关，保持精简。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Reddit 社群整理的 Claude Token 省量三大策略：上下文管理（精簡 CLAUDE.md、話題切換即 /clear）、提示詞精準化（禁用不必要的 Ultrathink、模型降級）、MCP 清理與本地預處理（可降低 token 消耗最多 99%）。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Context 是最大浪費源</strong>：每次對話都附帶完整歷史，CLAUDE.md 越長消耗越多；切換話題不開新對話是最常見的 token 浪費行為</li><li><strong>Ultrathink 應按需使用</strong>：深度思考模式只適合複雜邏輯，普通任務開啟是純粹浪費</li><li><strong>模型降級策略</strong>：Opus 用於深度推理，Sonnet 用於一般任務；選錯模型直接影響成本</li><li><strong>MCP 空跑消耗</strong>：即使未主動呼叫，掛載的 MCP Server 仍會佔用上下文 token</li><li><strong>本地預處理截斷輸入</strong>：用本地小模型（Llama 3 等）先壓縮長文本再投喂 Claude，可降低 token 消耗高達 99%</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>本地預處理節省幅度：最高 99%（文中聲稱，未附測試條件）</li><li>提及工具：<code>/clear</code>、<code>/memory</code>、MCP Server、Llama 3（本地預處理）</li><li>模型分層：Opus（深度邏輯）→ Sonnet（一般任務）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>本地預處理 99% 降幅</strong>：聲稱最高降低 99% token 消耗，但未說明基準條件（如何定義「幾千行日誌」），實際效果依任務類型差異大</li><li><strong>與 workspace 現有規則高度重疊</strong>：<code>token-efficiency.md</code>、<code>context-management.md</code> 已涵蓋多數策略，增量價值有限</li><li><strong>MCP 空跑說明有工程價值</strong>：「未主動呼叫的 MCP 仍消耗 context」這點在 workspace 規則中未明確點出，是可補充的 gotcha</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>MCP 空跑 gotcha、本地預處理思路可補充 token-efficiency.md</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>多數策略 workspace 已有；本地預處理截斷是相對少見的角度</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>有 99% 具體數字，但缺測試條件；Reddit 社群來源可信度中等</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>涵蓋 MCP 機制、Ultrathink 使用場景、模型降級策略</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>策略適用任何 Claude Code / Claude API 用戶</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.1/10</strong></td><td>7×0.3+5×0.2+5×0.2+6×0.15+7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：MCP 空跑消耗上下文這點是現有規則的 Known Gotcha 補充；本地預處理思路可強化 token-efficiency.md 的工具建議區塊。</p>',36)])])}const m=a(n,[["render",d]]);export{p as __pageData,m as default};
